// Community boards from the 2026 five-clue record wave, decoded from the
// e2.bucas.name links shared by the authors. Every score/piece-count was
// re-verified with scoreCells (src/lib/bucas.ts) before publishing.
//
// FiveClueRecord: full 256-piece boards, scored by matched edges out of 480,
// each respecting all five official clue placements (starter #139 + hints
// #208/#255/#181/#249). Source: "Record of Eternity2 with 5 hints ?" thread,
// eternity2@groups.io, June-July 2026 (topic 120056886). Benjamin Riotte's
// 464 broke Bruno Gauthier's 460, which had stood since 2023.
//
// LinearPartial: partial boards (not full solutions) built as linear runs or
// spiral-in constructions; the number is the placed-piece / continuous-run
// count, NOT an edge score. Source: One Small Step, community Discord.

export interface FiveClueRecord {
  id: string;
  score: number;
  author: string;
  /** e.g. tile-distance from the public 460; empty when not reported. */
  note: string;
  /** e2.bucas.name URL hash (also loads in our own /viewer). */
  params: string;
}

export interface LinearPartial {
  id: string;
  /** Who built it (McGavin, One Small Step, …). */
  author: string;
  /** As posted (dd/mm/yyyy for Discord, yyyy-mm-dd for the groups.io archive). */
  date: string;
  /** Total pieces placed on the board, re-counted from board_edges (a cell is
   *  placed iff not all-grey). NOT the author's caption number, which for a
   *  "continuous run" board is the run length, not the placement count. */
  placed: number;
  /** How many of the five official clue pieces sit at their official positions,
   *  verified from `board_edges` (pieces are distinct up to rotation, so the
   *  edges name each clue piece — no board_pieces needed): 5 = full record,
   *  <5 = partial, null = clue compliance not verified / not applicable. */
  hints: number | null;
  /** Construction metric, so unlike lineages don't get ranked against each
   *  other: a spiral-in fill, a linear run, or a continuous-run length. */
  metric: "spiral-in" | "linear" | "continuous-run";
  /** Primary source: a groups.io message number, or "Discord". */
  source: string;
  /** A short caveat when one applies (e.g. "starter piece only"). */
  note: string;
  params: string;
}

